function shuffleRnd(arr, rnd = Math.random) {
  const a = [...arr];
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(rnd() * (i + 1));
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a;
}
function stripNikud2(he = "") {
  return he.replace(/[\u0591-\u05C7]/g, "");
}
function pickDistractors(pool, excludeId, n, rnd) {
  const seen = /* @__PURE__ */ new Set([excludeId]);
  const uniq = pool.filter((x) => x && !seen.has(x.id) && seen.add(x.id));
  return shuffleRnd(uniq, rnd).slice(0, n);
}
var genChoice4 = {
  id: "choice4",
  mode: "choice",
  build(item, _pool, rnd = Math.random) {
    if (!item?.options?.length) return null;
    const shuffled = shuffleRnd(item.options, rnd);
    const options = shuffled.map((o, i) => ({ id: String(i), label: o }));
    const answerIdx = shuffled.indexOf(item.answer);
    return {
      gen: "choice4",
      mode: "choice",
      prompt: item.prompt,
      hebrew: item.hebrew || null,
      speak: item.hebrew || null,
      options,
      answerId: String(answerIdx)
    };
  }
};
var genWordRu = {
  id: "word_ru",
  mode: "choice",
  build(word, pool = [], rnd = Math.random) {
    if (!word?.ru) return null;
    const ds = pickDistractors(pool.length >= 4 ? pool : [word], word.id, 3, rnd);
    const options = shuffleRnd([word, ...ds], rnd).map((w) => ({ id: w.id, label: w.ru }));
    return {
      gen: "word_ru",
      mode: "choice",
      prompt: "\u0427\u0442\u043E \u044D\u0442\u043E \u0437\u043D\u0430\u0447\u0438\u0442?",
      hebrew: word.he,
      speak: word.he,
      options,
      answerId: word.id,
      itemId: word.id
    };
  }
};
var genWordHe = {
  id: "word_he",
  mode: "choice",
  build(word, pool = [], rnd = Math.random) {
    if (!word?.he) return null;
    const ds = pickDistractors(pool.length >= 4 ? pool : [word], word.id, 3, rnd);
    const options = shuffleRnd([word, ...ds], rnd).map((w) => ({ id: w.id, label: w.he, labelHe: w.he }));
    return {
      gen: "word_he",
      mode: "choice",
      prompt: `\u041A\u0430\u043A \u043D\u0430 \u0438\u0432\u0440\u0438\u0442\u0435 \xAB${word.ru}\xBB?`,
      hebrew: null,
      speak: word.he,
      options,
      answerId: word.id,
      itemId: word.id
    };
  }
};
var genNoNikud = {
  id: "no_nikud",
  mode: "choice",
  build(word, pool = [], rnd = Math.random) {
    const q = genWordRu.build(word, pool, rnd);
    if (!q) return null;
    const bare = word.plain || stripNikud2(word.he);
    if (!bare || bare === word.he) return null;
    return { ...q, gen: "no_nikud", hebrew: bare, prompt: "\u041F\u0440\u043E\u0447\u0438\u0442\u0430\u0439 \u0431\u0435\u0437 \u043E\u0433\u043B\u0430\u0441\u043E\u0432\u043E\u043A. \u0427\u0442\u043E \u044D\u0442\u043E \u0437\u043D\u0430\u0447\u0438\u0442?" };
  }
};
var genTyping = {
  id: "typing",
  mode: "typing",
  build(word, _pool, _rnd) {
    if (!word?.he) return null;
    return {
      gen: "typing",
      mode: "typing",
      prompt: `\u041D\u0430\u043F\u0435\u0447\u0430\u0442\u0430\u0439 \u043D\u0430 \u0438\u0432\u0440\u0438\u0442\u0435: \xAB${word.ru}\xBB`,
      hebrew: null,
      speak: word.he,
      answerId: word.plain || stripNikud2(word.he),
      // сравнение без огласовок
      itemId: word.id
    };
  }
};
var genPhraseBuild = {
  id: "phrase_build",
  mode: "choice",
  build(phrase, pool = [], rnd = Math.random) {
    if (!phrase?.he || !phrase?.ru) return null;
    const ds = pickDistractors(pool.filter((p2) => p2.he), phrase.id, 3, rnd);
    const options = shuffleRnd([phrase, ...ds], rnd).map((p2) => ({ id: p2.id, label: p2.he, labelHe: p2.he }));
    return {
      gen: "phrase_build",
      mode: "choice",
      prompt: `\u041A\u0430\u043A \u0441\u043A\u0430\u0437\u0430\u0442\u044C: \xAB${phrase.ru}\xBB?`,
      hebrew: null,
      speak: phrase.he,
      options,
      answerId: phrase.id,
      itemId: phrase.id
    };
  }
};
var GENERATORS = {
  [genChoice4.id]: genChoice4,
  [genWordRu.id]: genWordRu,
  [genWordHe.id]: genWordHe,
  [genNoNikud.id]: genNoNikud,
  [genTyping.id]: genTyping,
  [genPhraseBuild.id]: genPhraseBuild
};
function buildQuestion(genId, source, pool, rnd = Math.random) {
  const g3 = GENERATORS[genId];
  return g3 ? g3.build(source, pool, rnd) : null;
}
function buildSession(plan, rnd = Math.random) {
  const out = [];
  for (const layer of plan) {
    const srcs = shuffleRnd(layer.sources || [], rnd).slice(0, layer.take ?? layer.sources?.length ?? 0);
    for (const s of srcs) {
      const q = buildQuestion(layer.gen, s, layer.pool || layer.sources || [], rnd);
      if (q) out.push(q);
    }
  }
  return shuffleRnd(out, rnd);
}

